mapper.select:
and order_id = #{orderId}
and coalesce(nullif(main_order_no, ''), cast(order_id as char)) like concat('%', #{mainOrderNo}, '%')
and coalesce(nullif(sub_order_no, ''), concat(cast(order_id as char), '-', order_item_id)) like concat('%', #{subOrderNo}, '%')
and shop_name like concat('%', #{shopName}, '%') and product_name like concat('%', #{productName}, '%') and order_status = #{orderStatus}
order by pay_time desc, order_item_id desc

select item_id as salesItemId, sales_id as salesId
from erp_sales_order_item
where item_id = #{salesItemId}

mapper.insert:
insert into erp_sales_shipment(
    shipment_no, sales_id, sales_no, main_order_no, package_no,
    warehouse_id, warehouse_name, logistics_company, logistics_no,
    idempotency_key, shipment_status, version, create_by, create_time, update_time, remark
) values(
    #{shipmentNo}, #{salesId}, #{salesNo}, #{mainOrderNo}, #{packageNo},
    #{warehouseId}, #{warehouseName}, #{logisticsCompany}, #{logisticsNo},
    #{idempotencyKey}, 'draft', 0, #{createBy}, sysdate(), sysdate(), #{remark}
)

insert into erp_sales_fulfillment_log(
    sales_id, sales_item_id, biz_type, biz_no, action_type,
    from_status, to_status, operator_name, action_time, detail
) values(
    #{salesId}, #{salesItemId}, #{bizType}, #{bizNo}, #{actionType},
    #{fromStatus}, #{toStatus}, #{operatorName}, sysdate(), #{detail}
)
